import numpy as np

def sigmoid(x):
    return 1 / (1 + np.exp(-x))

def sigmoid_derivative(x):
    """Sigmoid er derivative = sigmoid(x) * (1 - sigmoid(x))"""
    s = sigmoid(x)
    return s * (1 - s)

x = np.linspace(-6, 6, 100)

# Derivative at different points
for val in [-2, 0, 2, 5]:
    print(f'sigmoid({val}) = {sigmoid(val):.4f}, '
          f"sigmoid'({val}) = {sigmoid_derivative(val):.4f}")

# Notice: derivative max at x=0 (0.25), vanishes at extremes!
# Eita holo vanishing gradient problem er root cause
print(f'\nMax derivative: {np.max(sigmoid_derivative(x)):.4f}')  # ~0.25
print(f'sigmoid\'(10) = {sigmoid_derivative(10):.8f}')  # almost 0!
